using BgControls.Collections.Generic;namespace BgControls.Windows.Input.Touch;/// <summary>/// 滑动手势识别器，用于处理滑动手势及滑动后的惯性逻辑./// </summary>public class SwipeGestureRecognizer : GestureRecognizerBase{    private WeakReferenceList<TouchEventHandler> swipeStartedHandlers;    private WeakReferenceList<SwipeEventHandler> swipeHandlers;    private WeakReferenceList<TouchEventHandler> swipeFinishedHandlers;    private WeakReferenceList<RoutedEventHandler> swipeInertiaStartedHandlers;    private WeakReferenceList<SwipeInertiaEventHandler> swipeInertiaHandlers;    private WeakReferenceList<RoutedEventHandler> swipeInertiaFinishedHandlers;    private SwipeHelper? swipeHelper;    /// <summary>    /// Initializes a new instance of the <see cref="SwipeGestureRecognizer"/> class.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    internal SwipeGestureRecognizer(UIElement element)        : base(element)    {        // 初始化各类事件处理程序的弱引用列表.        this.swipeStartedHandlers = new WeakReferenceList<TouchEventHandler>();        this.swipeHandlers = new WeakReferenceList<SwipeEventHandler>();        this.swipeFinishedHandlers = new WeakReferenceList<TouchEventHandler>();        this.swipeInertiaStartedHandlers = new WeakReferenceList<RoutedEventHandler>();        this.swipeInertiaHandlers = new WeakReferenceList<SwipeInertiaEventHandler>();        this.swipeInertiaFinishedHandlers = new WeakReferenceList<RoutedEventHandler>();    }    /// <summary>    /// 处理触控进入事件.    /// </summary>    /// <param name="args">事件参数.</param>    public override void OnTouchEnter(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        GestureRecognizerBase.VerifyElementsMismatch(this.Element, args.Element);    }    /// <summary>    /// 处理触控按下事件.    /// </summary>    /// <param name="args">事件参数.</param>    public override void OnTouchDown(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        GestureRecognizerBase.VerifyElementsMismatch(this.Element, args.Element);        // 如果当前没有正在处理的滑动，或者触控 ID 匹配，则初始化滑动手势辅助工具.        if (this.swipeHelper == null || this.swipeHelper.TouchId == args.TouchId)        {            this.swipeHelper = new SwipeHelper(this.Element, args.TouchId, this);            this.swipeHelper.OnTouchDown(args);        }    }    /// <summary>    /// 处理触控移动事件.    /// </summary>    /// <param name="args">事件参数.</param>    public override void OnTouchMove(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        GestureRecognizerBase.VerifyElementsMismatch(this.Element, args.Element);        // 仅在触控 ID 匹配时处理移动逻辑.        if (this.swipeHelper != null && this.swipeHelper.TouchId == args.TouchId)        {            this.swipeHelper.OnTouchMove(args);        }    }    /// <summary>    /// 处理触控抬起事件.    /// </summary>    /// <param name="args">事件参数.</param>    public override void OnTouchUp(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        GestureRecognizerBase.VerifyElementsMismatch(this.Element, args.Element);        if (this.swipeHelper != null && this.swipeHelper.TouchId == args.TouchId)        {            this.swipeHelper.OnTouchUp(args);        }    }    /// <summary>    /// 处理触控离开事件.    /// </summary>    /// <param name="args">事件参数.</param>    public override void OnTouchLeave(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        GestureRecognizerBase.VerifyElementsMismatch(this.Element, args.Element);        if (this.swipeHelper != null && this.swipeHelper.TouchId == args.TouchId)        {            this.swipeHelper.OnTouchLeave(args);        }    }    /// <summary>    /// 当请求停止手势识别时触发.    /// </summary>    public override void OnCeaseGesturesRequested()    {        if (this.swipeHelper != null)        {            this.swipeHelper.CeaseGesture();        }    }    /// <summary>    /// 获取所有注册的处理程序总数.    /// </summary>    /// <returns>处理程序总和.</returns>    internal int GetTotalHandlersCount()    {        // 累加所有手势阶段和惯性阶段的处理程序数量.        return this.swipeStartedHandlers.Count +               this.swipeHandlers.Count +               this.swipeFinishedHandlers.Count +               this.swipeInertiaStartedHandlers.Count +               this.swipeInertiaHandlers.Count +               this.swipeInertiaFinishedHandlers.Count;    }    /// <summary>    /// 添加滑动开始事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void AddSwipeStartedHandler(TouchEventHandler handler)    {        this.swipeStartedHandlers.Add(handler);        this.HasGestureHandlers = true;    }    /// <summary>    /// 移除滑动开始事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void RemoveSwipeStartedHandler(TouchEventHandler handler)    {        this.swipeStartedHandlers.Remove(handler);        this.HasGestureHandlers = this.GetTotalHandlersCount() > 0;        this.DoSwipeHelperMaintenance();    }    /// <summary>    /// 添加滑动中事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void AddSwipeHandler(SwipeEventHandler handler)    {        this.swipeHandlers.Add(handler);        this.HasGestureHandlers = true;    }    /// <summary>    /// 移除滑动中事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void RemoveSwipeHandler(SwipeEventHandler handler)    {        this.swipeHandlers.Remove(handler);        this.HasGestureHandlers = this.GetTotalHandlersCount() > 0;        this.DoSwipeHelperMaintenance();    }    /// <summary>    /// 添加滑动完成事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void AddSwipeFinishedHandler(TouchEventHandler handler)    {        this.swipeFinishedHandlers.Add(handler);        this.HasGestureHandlers = true;    }    /// <summary>    /// 移除滑动完成事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void RemoveSwipeFinishedHandler(TouchEventHandler handler)    {        this.swipeFinishedHandlers.Remove(handler);        this.HasGestureHandlers = this.GetTotalHandlersCount() > 0;        this.DoSwipeHelperMaintenance();    }    /// <summary>    /// 添加滑动惯性开始事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void AddSwipeInertiaStartedHandler(RoutedEventHandler handler)    {        this.swipeInertiaStartedHandlers.Add(handler);        this.HasGestureHandlers = true;    }    /// <summary>    /// 移除滑动惯性开始事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void RemoveSwipeInertiaStartedHandler(RoutedEventHandler handler)    {        this.swipeInertiaStartedHandlers.Remove(handler);        this.HasGestureHandlers = this.GetTotalHandlersCount() > 0;        this.DoSwipeHelperMaintenance();    }    /// <summary>    /// 添加滑动惯性中事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void AddSwipeInertiaHandler(SwipeInertiaEventHandler handler)    {        this.swipeInertiaHandlers.Add(handler);        this.HasGestureHandlers = true;    }    /// <summary>    /// 移除滑动惯性中事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void RemoveSwipeInertiaHandler(SwipeInertiaEventHandler handler)    {        this.swipeInertiaHandlers.Remove(handler);        this.HasGestureHandlers = this.GetTotalHandlersCount() > 0;        this.DoSwipeHelperMaintenance();    }    /// <summary>    /// 添加滑动惯性完成事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void AddSwipeInertiaFinishedHandler(RoutedEventHandler handler)    {        this.swipeInertiaFinishedHandlers.Add(handler);        this.HasGestureHandlers = true;    }    /// <summary>    /// 移除滑动惯性完成事件处理程序.    /// </summary>    /// <param name="handler">处理程序委托.</param>    internal void RemoveSwipeInertiaFinishedHandler(RoutedEventHandler handler)    {        this.swipeInertiaFinishedHandlers.Remove(handler);        this.HasGestureHandlers = this.GetTotalHandlersCount() > 0;        this.DoSwipeHelperMaintenance();    }    /// <summary>    /// 释放指定的滑动辅助工具实例.    /// </summary>    /// <param name="helper">滑动辅助工具.</param>    internal void ReleaseHelper(SwipeHelper helper)    {        // 如果传入的辅助工具是当前持有的实例，则将其置为空.        if (this.swipeHelper == helper)        {            this.swipeHelper = null;        }    }    /// <summary>    /// 执行滑动辅助工具的维护逻辑.    /// </summary>    private void DoSwipeHelperMaintenance()    {        // 如果不再有手势处理程序，则强制停止当前可能正在进行的滑动.        if (!this.HasGestureHandlers && this.swipeHelper != null)        {            this.swipeHelper.CeaseGesture();        }    }}